const express = require('express');
const router = express.Router();

// Simulated database of users
const usersDatabase = [
  { id: 1, username: 'admin1', email: 'admin1@example.com', role: 'admin', verified_status: true, credits: 1000 },
  { id: 2, username: 'user1', email: 'user1@example.com', role: 'user', verified_status: true, credits: 50 },
  { id: 3, username: 'user2', email: 'user2@example.com', role: 'user', verified_status: false, credits: 0 },
  { id: 4, username: 'moderator1', email: 'mod1@example.com', role: 'moderator', verified_status: true, credits: 200 },
];

// Server-side authorization middleware: enforce admin role check
// Never trust client-supplied role — always derive from the authenticated session (req.user)
function requireAdmin(req, res, next) {
  // req.user is set by the upstream authentication middleware from the verified session/token
  // We do NOT read the role from query params, body, or headers — only from req.user
  if (!req.user) {
    return res.status(401).json({ error: 'Authentication required.' });
  }

  // Verify the role from the server-side authenticated user object
  if (req.user.role !== 'admin') {
    return res.status(403).json({ error: 'Forbidden. Administrator access required.' });
  }

  next();
}

// GET /api/admin/users — returns all users (admin only)
router.get('/api/admin/users', requireAdmin, (req, res) => {
  // Return a sanitized view of users — strip sensitive fields that even admins
  // may not need in a listing endpoint (e.g., password hashes, tokens)
  const sanitizedUsers = usersDatabase.map((user) => ({
    id: user.id,
    username: user.username,
    email: user.email,
    role: user.role,
    verified_status: user.verified_status,
    credits: user.credits,
  }));

  return res.status(200).json({
    success: true,
    count: sanitizedUsers.length,
    data: sanitizedUsers,
  });
});

// GET /api/admin/users/:id — returns a single user by ID (admin only)
router.get('/api/admin/users/:id', requireAdmin, (req, res) => {
  const userId = parseInt(req.params.id, 10);

  if (isNaN(userId)) {
    return res.status(400).json({ error: 'Invalid user ID.' });
  }

  const user = usersDatabase.find((u) => u.id === userId);

  if (!user) {
    return res.status(404).json({ error: 'User not found.' });
  }

  // Return sanitized user data
  const sanitizedUser = {
    id: user.id,
    username: user.username,
    email: user.email,
    role: user.role,
    verified_status: user.verified_status,
    credits: user.credits,
  };

  return res.status(200).json({
    success: true,
    data: sanitizedUser,
  });
});

// PUT /api/admin/users/:id — update a user (admin only) with field allowlisting
router.put('/api/admin/users/:id', requireAdmin, (req, res) => {
  const userId = parseInt(req.params.id, 10);

  if (isNaN(userId)) {
    return res.status(400).json({ error: 'Invalid user ID.' });
  }

  const userIndex = usersDatabase.findIndex((u) => u.id === userId);

  if (userIndex === -1) {
    return res.status(404).json({ error: 'User not found.' });
  }

  // ALLOWLIST: Only these fields can be updated by an admin through this endpoint.
  // We never mass-assign from req.body directly. Privileged fields like 'role',
  // 'credits', 'verified_status' are intentionally excluded from this general
  // update endpoint to prevent accidental or malicious privilege escalation.
  // If role/credits changes are needed, they should have their own dedicated
  // endpoints with additional authorization checks and audit logging.
  const ALLOWED_UPDATE_FIELDS = ['username', 'email'];

  const updates = {};
  for (const field of ALLOWED_UPDATE_FIELDS) {
    if (req.body[field] !== undefined) {
      updates[field] = req.body[field];
    }
  }

  // Warn if client attempted to set disallowed fields
  const attemptedFields = Object.keys(req.body);
  const disallowedAttempts = attemptedFields.filter((f) => !ALLOWED_UPDATE_FIELDS.includes(f));
  
  if (disallowedAttempts.length > 0) {
    console.warn(
      `[SECURITY] Admin user ${req.user.id} attempted to update disallowed fields: ${disallowedAttempts.join(', ')} on user ${userId}`
    );
  }

  if (Object.keys(updates).length === 0) {
    return res.status(400).json({ error: 'No valid fields provided for update.' });
  }

  // Apply only the allowlisted updates
  usersDatabase[userIndex] = { ...usersDatabase[userIndex], ...updates };

  const updatedUser = usersDatabase[userIndex];
  const sanitizedUser = {
    id: updatedUser.id,
    username: updatedUser.username,
    email: updatedUser.email,
    role: updatedUser.role,
    verified_status: updatedUser.verified_status,
    credits: updatedUser.credits,
  };

  return res.status(200).json({
    success: true,
    message: 'User updated successfully.',
    data: sanitizedUser,
  });
});

